const dateDiff = (_date1, _date2) => {
    var diffDate_1 = _date1 instanceof Date ? _date1 : new Date(_date1);
    var diffDate_2 = _date2 instanceof Date ? _date2 : new Date(_date2);

    diffDate_1 = new Date(diffDate_1.getFullYear(), diffDate_1.getMonth() + 1, diffDate_1.getDate());
    diffDate_2 = new Date(diffDate_2.getFullYear(), diffDate_2.getMonth() + 1, diffDate_2.getDate());

    var diff = Math.abs(diffDate_2.getTime() - diffDate_1.getTime());
    diff = Math.ceil(diff / (1000 * 3600 * 24));

    return diff;
};

const leadingZeros = (n, digits) => {
    let zero = "";
    n = n.toString();
    if (n.length < digits) {
        for (let i = 0; i < digits - n.length; i++) zero += "0";
    }
    return zero + n;
};

const getCurrentMonthDay = () => {
    let d = new Date();
    let s = leadingZeros(d.getMonth() + 1, 2) + leadingZeros(d.getDate(), 2);
    return s;
};

const getCurrentDate = () => {
    let d = new Date();
    let s =
        leadingZeros(d.getFullYear(), 4) +
        "-" +
        leadingZeros(d.getMonth() + 1, 2) +
        "-" +
        leadingZeros(d.getDate(), 2);
    return s;
};

const getCurrentTimestamp = () => {
    let d = new Date();
    let s =
        leadingZeros(d.getFullYear(), 4) +
        "-" +
        leadingZeros(d.getMonth() + 1, 2) +
        "-" +
        leadingZeros(d.getDate(), 2) +
        " " +
        leadingZeros(d.getHours(), 2) +
        ":" +
        leadingZeros(d.getMinutes(), 2) +
        ":" +
        leadingZeros(d.getSeconds(), 2);
    return s;
};

const getCurrentTimestampWithNoDelimeter = () => {
    let d = new Date();
    let s =
        leadingZeros(d.getFullYear(), 4) +
        leadingZeros(d.getMonth() + 1, 2) +
        leadingZeros(d.getDate(), 2) +
        leadingZeros(d.getHours(), 2) +
        leadingZeros(d.getMinutes(), 2) +
        leadingZeros(d.getSeconds(), 2);
    return s;
};

const getDate = date => {
    let d = new Date(date);
    let s =
        leadingZeros(d.getFullYear(), 4) +
        "-" +
        leadingZeros(d.getMonth() + 1, 2) +
        "-" +
        leadingZeros(d.getDate(), 2);
    return s;
};

const getMonth = (date) => {
    let d = new Date(date);
    let s = leadingZeros(d.getFullYear(), 4) + '-' + leadingZeros(d.getMonth() + 1, 2);
    return s;
}

const getMonthDate = date => {
    let d = new Date(date);
    let s = leadingZeros(d.getMonth() + 1, 2) + "-" + leadingZeros(d.getDate(), 2);
    return s;
};

