<template>
    <div>
        <div class="detection_wrap">
            <h4>드론 탐지 창 설정</h4>
            <div>
                <p class="tit">채우기</p>
                <div class="option fill_opacity">
                    <span class="txt">투명도</span>
                    <div>
                        <!-- <v-slider v-model="fillOpacity.val" :color="fillOpacity.color" hide-details max="10" min="0"></v-slider>
                        <input type="number" max="10" min="0" v-model="fillOpacity.val" /> -->

                        <v-slider v-model="model.FILL_TRANSPARENCY" :color="fillOpacity.color" hide-details max="10" min="0"></v-slider>
                        <input type="number" max="10" min="0" v-model="model.FILL_TRANSPARENCY" />
                    </div>
                </div>
                <p class="tit etc">기타</p>
                <div class="option check_screen">
                    <v-checkbox v-model="model.DISPLAY_TYPE" label="화면에 표시하기" hide-details />
                </div>
            </div>
        </div>
        <div class="btn_area">
            <v-btn elevation="3" color="primary" @click="doSave"> 확인 </v-btn>
        </div>

        <AlertModal :params="alertModalParams"></AlertModal>
    </div>
</template>

<script>
import * as DateUtil from "@/common/DateUtil";
import * as LogUtil from "@/common/LogUtil";
import * as MapConfigDevice from "@/rest/MapConfigDevice";

import AlertModal from '@/components/modal/AlertModal';

export default {
  components: {
    AlertModal
  },
  data: () => ({
    alertModalParams: { isOpened: false, title: '', message: ''},

    fillGroup: 1,
    fillColor: 0,
    fillColorSel: false,
    fillOpacity: { val: 10, color: '#2a85ff' },
    screenOn: false,

    model: {},
  }),
  mounted() {
    this.initDataList();
  },
  methods: {
    showAlertModal(msg) {
      this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
    },
    initDataList(condition) {
      let options = {
        conditions: [
          { clause: 'and', name: 'CONFIG_TYPE', operator: '=', value: 'D'},
        ],
        orderBys: [
          { name: 'MAP_CONFIG_DEVICE_ID', operator: 'asc'}
        ],
        paging: { pageNo: 1, pageSize: 100 }
      };
      if(condition != null) options.conditions.push(condition);

      MapConfigDevice.listByCondition(options).then(res => {
        if(res.data.RES_CODE>=0) {
          this.model = res.data.ITEMS.length>0 ? res.data.ITEMS[0] : {
            MAP_CONFIG_DEVICE_ID: -1,
            CONFIG_TYPE: 'D',
            FILL_TRANSPARENCY: 10,
            DISPLAY_TYPE: 1,
            CREATED: null
          };
          LogUtil.debug("MapDetection: initDataList(): this.model=", this.model);
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
      });
    },
    doSave() {
      this.model.CREATED = this.model.CREATED !== null ? DateUtil.getTimestamp(this.model.CREATED) : DateUtil.getCurrentTimestamp(),
      this.model.UPDATED = DateUtil.getCurrentTimestamp(),
      LogUtil.debug('MapDetection: doSave(): this.model=', this.model);
      MapConfigDevice.save(this.model).then(res => {
        if(res.data.RES_CODE>=0) {
          LogUtil.debug('MapDetection: doSave(): res.data=', res.data);
          if(this.model.MAP_CONFIG_DEVICE_ID === -1) {
            this.model.MAP_CONFIG_DEVICE_ID = res.data.ITEM.insertId;
          }
          LogUtil.debug('MapDetection: doSave(): this.model.MAP_CONFIG_DEVICE_ID=', this.model.MAP_CONFIG_DEVICE_ID);
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
      });
    },
  },
};
</script>

<style lang="scss" scoped>
.detection_wrap {
    width: 600px;
    margin: 60px auto 0;
    border: 1px solid $color-main03;
    border-radius: 10px;
    h4 {
        @include centerAlign();
        height: 61px;
        border-bottom: 1px solid $color-main03;
        font: {
            size: 20px;
        }
    }
    & > div {
        padding: 19px 50px 30px;
        .tit {
            margin-bottom: 13px;
            font: {
                size: 18px;
                weight: 600;
            }
            &.etc {
                margin-top: 40px;
            }
        }
        .option {
            margin-top: 0;
            border: 1px solid #ccc;
            border-radius: 10px;
            &.fill_opacity {
                padding: 30px 22px;
                & > div {
                    display: flex;
                    input {
                        width: 60px;
                        height: 38px;
                        margin: 0 10px;
                        border: 1px solid #ccc;
                        border-radius: 8px;
                        text-align: center;
                    }
                }
            }
            &.check_screen {
                padding: 22px;
                .v-input--checkbox {
                    margin-top: 0;
                }
            }
        }
    }
}
.btn_area {
    @include wCenterAlign();
    width: 600px;
    margin: 50px auto 0;
}
</style>
